class Solution:
    def findMaximumNumber(self, k: int, x: int) -> int:
        def count_set_bits_at_positions(num: int, x: int) -> int:
            count = 0
            position = x
            while position <= num.bit_length():
                # Count how many numbers from 1 to num have a set bit at position
                # The number of full cycles is (num + 1) // (1 << position)
                # Each full cycle contributes (1 << (position - 1)) set bits at this position
                full_cycles = (num + 1) // (1 << position)
                count += full_cycles * (1 << (position - 1))
                # Count the remaining numbers
                remainder = (num + 1) % (1 << position)
                count += max(0, remainder - (1 << (position - 1)))
                position += x
            return count

        def total_price(num: int, x: int) -> int:
            return count_set_bits_at_positions(num, x)

        left = 1
        right = 10**18  # A safe upper bound
        answer = 0

        while left <= right:
            mid = (left + right) // 2
            price = total_price(mid, x)
            if price <= k:
                answer = mid
                left = mid + 1
            else:
                right = mid - 1

        return answer
